import {
  pgTable,
  uuid,
  text,
  integer,
  real,
  boolean,
  jsonb,
  timestamp,
  primaryKey,
} from "drizzle-orm/pg-core";
import { GameState } from "@/types/game";

// ─── players ──────────────────────────────────────────────────────────────────

export const players = pgTable("players", {
  id: uuid("id").defaultRandom().primaryKey(),
  email: text("email").notNull().unique(),
  displayName: text("display_name").notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

// ─── game_sessions ────────────────────────────────────────────────────────────
// state is stored as a JSON blob — one read/write per turn, no joins needed.

export const gameSessions = pgTable("game_sessions", {
  id: uuid("id").defaultRandom().primaryKey(),
  playerId: uuid("player_id")
    .notNull()
    .references(() => players.id, { onDelete: "cascade" }),
  state: jsonb("state").$type<GameState>().notNull(),
  isComplete: boolean("is_complete").default(false).notNull(),
  acumenScore: real("acumen_score"),         // null until game ends
  startedAt: timestamp("started_at").defaultNow().notNull(),
  completedAt: timestamp("completed_at"),
});

// ─── narrative_beats ──────────────────────────────────────────────────────────
// Seeded by narrative-agent. Read-only at runtime.

export const narrativeBeats = pgTable("narrative_beats", {
  id: text("id").primaryKey(),              // e.g. "beat_00", "beat_01"
  round: integer("round").notNull(),         // 0 = preamble, 1-3 = rounds
  title: text("title").notNull(),
  storyText: text("story_text").notNull(),
  orderIndex: integer("order_index").notNull(), // position within round
});

// ─── narrative_choices ────────────────────────────────────────────────────────
// The public-facing choices for each beat. Safe to expose to client.

export const narrativeChoices = pgTable("narrative_choices", {
  id: text("id").primaryKey(),              // e.g. "choice_01a"
  beatId: text("beat_id")
    .notNull()
    .references(() => narrativeBeats.id, { onDelete: "cascade" }),
  label: text("label").notNull(),
  immediateFeedback: text("immediate_feedback").notNull(),
  nextBeatId: text("next_beat_id"),         // null = default progression
});

// ─── choice_impacts ───────────────────────────────────────────────────────────
// PRIVATE — backend only. Never exposed in API responses to client.
// RLS: no public access.

export const choiceImpacts = pgTable("choice_impacts", {
  choiceId: text("choice_id")
    .primaryKey()
    .references(() => narrativeChoices.id, { onDelete: "cascade" }),
  capitalDelta: real("capital_delta").default(0).notNull(),
  reputationDelta: real("reputation_delta").default(0).notNull(),
  networkDelta: real("network_delta").default(0).notNull(),
  momentumDelta: real("momentum_delta").default(0).notNull(),
  autonomyDelta: real("autonomy_delta").default(0).notNull(),
  innovativenessDelta: real("innovativeness_delta").default(0).notNull(),
  proactivenessDelta: real("proactiveness_delta").default(0).notNull(),
  riskTakingDelta: real("risk_taking_delta").default(0).notNull(),
  competitiveAggressivenessDelta: real("competitive_aggressiveness_delta").default(0).notNull(),
  flagUpdates: jsonb("flag_updates").$type<Record<string, boolean>>().default({}).notNull(),
});

import {
  GameState,
  ChoiceImpact,
  NarrativeId,
  ChoiceId,
  Resources,
  Dimensions,
} from "@/types/game";

// ─── createInitialState ───────────────────────────────────────────────────────

export function createInitialState(playerId: string): GameState {
  return {
    session: {
      currentNarrativeId: "beat_00",
      isStoryComplete: false,
    },
    history: [],
    resources: {
      v_capital: 10000,
      reputation: 50,
      network: 10,
      momentumMultiplier: 1.0,
    },
    dimensions: {
      autonomy: 0,
      innovativeness: 0,
      proactiveness: 0,
      riskTaking: 0,
      competitiveAggressiveness: 0,
    },
    flags: {
      hasDebt: false,
      hiredTeam: false,
    },
  };
}

// ─── clampCapital ─────────────────────────────────────────────────────────────

export function clampCapital(value: number): number {
  return Math.max(0, value);
}

// ─── isDuplicateSubmission ────────────────────────────────────────────────────

export function isDuplicateSubmission(
  state: GameState,
  narrativeId: NarrativeId,
  choiceId: ChoiceId
): boolean {
  return state.history.some(
    (entry) => entry.narrativeId === narrativeId && entry.choiceId === choiceId
  );
}

// ─── applyChoiceToState ───────────────────────────────────────────────────────

export function applyChoiceToState(
  state: GameState,
  impact: ChoiceImpact,
  nextNarrativeId: NarrativeId
): GameState {
  const { momentumMultiplier } = state.resources;

  // Apply resource deltas
  const newResources: Resources = { ...state.resources };
  for (const key of Object.keys(impact.resourceDeltas) as (keyof Resources)[]) {
    const delta = impact.resourceDeltas[key] ?? 0;
    if (key === "v_capital") {
      newResources.v_capital = clampCapital(
        state.resources.v_capital + delta * momentumMultiplier
      );
    } else {
      (newResources[key] as number) = (state.resources[key] as number) + delta;
    }
  }

  // Apply dimension deltas
  const newDimensions: Dimensions = { ...state.dimensions };
  for (const key of Object.keys(impact.dimensionDeltas) as (keyof Dimensions)[]) {
    const delta = impact.dimensionDeltas[key] ?? 0;
    newDimensions[key] = state.dimensions[key] + delta;
  }

  // Apply flag updates, then set hasDebt if capital was clamped to 0
  const newFlags = { ...state.flags, ...impact.flagUpdates };
  if (newResources.v_capital === 0 && state.resources.v_capital > 0) {
    newFlags.hasDebt = true;
  }

  return {
    session: {
      ...state.session,
      currentNarrativeId: nextNarrativeId,
    },
    history: [
      ...state.history,
      {
        narrativeId: state.session.currentNarrativeId,
        choiceId: impact.choiceId,
        capitalBefore: state.resources.v_capital,
        capitalAfter: newResources.v_capital,
        timestamp: Date.now(),
      },
    ],
    resources: newResources,
    dimensions: newDimensions,
    flags: newFlags,
  };
}

// ─── processChoice ────────────────────────────────────────────────────────────

export function processChoice(
  state: GameState,
  choiceId: ChoiceId,
  impact: ChoiceImpact,
  nextNarrativeId: NarrativeId
): GameState {
  if (state.session.isStoryComplete) return state;
  if (isDuplicateSubmission(state, state.session.currentNarrativeId, choiceId)) return state;
  if (!isFinite(state.resources.momentumMultiplier) || isNaN(state.resources.momentumMultiplier)) {
    return state;
  }
  return applyChoiceToState(state, impact, nextNarrativeId);
}

// ─── completeStory ────────────────────────────────────────────────────────────

export function completeStory(state: GameState): GameState {
  return {
    ...state,
    session: { ...state.session, isStoryComplete: true },
  };
}

